@dataclass
class Vector3:
    x: float = 0.0
    y: float = 0.0
    z: float = 0.0

    def distance_to(self, other: 'Vector3') -> float:
        return math.sqrt(
            (self.x - other.x) ** 2 +
            (self.y - other.y) ** 2 +
            (self.z - other.z) ** 2
        )

    def to_dict(self):
        return {"x": self.x, "y": self.y, "z": self.z}

    @staticmethod
    def from_dict(d):
        return Vector3(d.get("x", 0), d.get("y", 0), d.get("z", 0))


@dataclass
class Obstacle:
    id: str
    position: Vector3
    size: Vector3  # bounding box half-extents
    obstacle_type: str = "wall"

    def to_dict(self):
        return {
            "id": self.id,
            "position": self.position.to_dict(),
            "size": self.size.to_dict(),
            "obstacle_type": self.obstacle_type
        }

    def intersects_ray(self, origin: Vector3, direction: Vector3) -> bool:
        """AABB ray intersection test for line of sight"""
        min_x = self.position.x - self.size.x
        max_x = self.position.x + self.size.x
        min_y = self.position.y - self.size.y
        max_y = self.position.y + self.size.y
        min_z = self.position.z - self.size.z
        max_z = self.position.z + self.size.z

        t_min = float('-inf')
        t_max = float('inf')

        for axis in ['x', 'y', 'z']:
            o = getattr(origin, axis)
            d = getattr(direction, axis)
            lo = locals()[f'min_{axis}']
            hi = locals()[f'max_{axis}']

            if abs(d) < 1e-8:
                if o < lo or o > hi:
                    return False
            else:
                t1 = (lo - o) / d
                t2 = (hi - o) / d
                if t1 > t2:
                    t1, t2 = t2, t1
                t_min = max(t_min, t1)
                t_max = min(t_max, t2)
                if t_min > t_max:
                    return False

        return t_min >= 0 and t_min <= 1.0


