class GameMap:
    def __init__(self, width: float = 2000.0, height: float = 2000.0):
        self.width = width
        self.height = height
        self.obstacles: List[Obstacle] = []
        self.loot_items: Dict[str, LootItem] = {}
        self._generate_map()

    def _generate_map(self):
        random.seed(42)
        # Generate buildings/obstacles
        for i in range(50):
            pos = Vector3(
                random.uniform(-self.width / 2, self.width / 2),
                0,
                random.uniform(-self.height / 2, self.height / 2)
            )
            size = Vector3(
                random.uniform(5, 30),
                random.uniform(3, 15),
                random.uniform(5, 30)
            )
            obstacle_type = random.choice(["building", "wall", "rock", "container"])
            self.obstacles.append(Obstacle(
                id=f"obs_{i}",
                position=pos,
                size=size,
                obstacle_type=obstacle_type
            ))

        # Generate loot spawns
        loot_types = [
            ("weapon", "rifle", 1),
            ("weapon", "shotgun", 1),
            ("weapon", "sniper", 1),
            ("weapon", "smg", 1),
            ("ammo", "rifle_ammo", 30),
            ("ammo", "shotgun_ammo", 8),
            ("ammo", "sniper_ammo", 5),
            ("ammo", "smg_ammo", 25),
            ("ammo", "pistol_ammo", 12),
            ("health", "medkit", 1),
            ("health", "bandage", 3),
            ("armor", "armor_plate", 1),
            ("grenade", "frag_grenade", 2),
        ]

        for i in range(200):
            loot_type, loot_name, qty = random.choice(loot_types)
            pos = Vector3(
                random.uniform(-self.width / 2, self.width / 2),
                0,
                random.uniform(-self.height / 2, self.height / 2)
            )
            item_id = f"loot_{i}"
            self.loot_items[item_id] = LootItem(
                id=item_id,
                position=pos,
                item_type=loot_type,
                item_name=loot_name,
                quantity=qty
            )

    def check_line_of_sight(self, from_pos: Vector3, to_pos: Vector3) -> bool:
        """Check if there's a clear line of sight between two positions"""
        direction = Vector3(
            to_pos.x - from_pos.x,
            to_pos.y - from_pos.y,
            to_pos.z - from_pos.z
        )
        for obstacle in self.obstacles:
            if obstacle.intersects_ray(from_pos, direction):
                return False
        return True

    def to_dict(self):
        return {
            "width": self.width,
            "height": self.height,
            "obstacles": [o.to_dict() for o in self.obstacles],
            "loot_items": {k: v.to_dict() for k, v in self.loot_items.items() if not v.picked_up}
        }


